const colors = { black: "#100B06", white: "#FFFFFF", cream: "#FFFFFF", red: "#E51D37" };

const W = 160;
const H = 120;
const ART_SCALE = 1.085;
const sequence = ["smile", "open", "tongue", "open"] as const;
const HOLD = 330;
const TRANSITION = 150;
const SEGMENT = HOLD + TRANSITION;
const LOOP = SEGMENT * sequence.length;

type LayerName = keyof typeof colors;
type Layer = { color: string; path: Path2D };

function compileLayerSet(layerSet: Record<string, string>) {
  return Object.entries(layerSet).map(([name, pathData]) => ({
    color: colors[name as LayerName],
    path: new Path2D(pathData),
  }));
}

function clamp(value: number, min = 0, max = 1) {
  return Math.max(min, Math.min(max, value));
}

function smoothstep(value: number) {
  value = clamp(value);
  return value * value * (3 - 2 * value);
}

function smootherstep(value: number) {
  value = clamp(value);
  return value * value * value * (value * (value * 6 - 15) + 10);
}

export default function FaceCanvas() {
  const canvasRef = useRef<HTMLCanvasElement>(null);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const canvasEl = canvas;

    const ctx = canvasEl.getContext("2d", { alpha: true, desynchronized: true });
    if (!ctx) return;
    const ctx2d = ctx;

    const staticLayers = compileLayerSet(data.static);
    const mouthLayers = Object.fromEntries(
      Object.entries(data.mouths).map(([name, layers]) => [name, compileLayerSet(layers)])
    ) as Record<string, Layer[]>;

    let frame = 0;
    let paused = false;
    let pauseTime = 0;
    let pausedTotal = 0;

    function prepareCanvas() {
      const rect = canvasEl.getBoundingClientRect();
      const dpr = Math.min(window.devicePixelRatio || 1, 5);
      const pixelWidth = Math.max(1, Math.round(rect.width * dpr));
      const pixelHeight = Math.max(1, Math.round(rect.height * dpr));

      if (canvasEl.width !== pixelWidth || canvasEl.height !== pixelHeight) {
        canvasEl.width = pixelWidth;
        canvasEl.height = pixelHeight;
      }

      ctx2d.setTransform(canvasEl.width / W, 0, 0, canvasEl.height / H, 0, 0);
      ctx2d.imageSmoothingEnabled = true;
      ctx2d.imageSmoothingQuality = "high";
    }

    function drawLayers(layers: Layer[], alpha = 1) {
      ctx2d.save();
      ctx2d.globalAlpha = alpha;
      for (const layer of layers) {
        ctx2d.fillStyle = layer.color;
        ctx2d.fill(layer.path, "evenodd");
      }
      ctx2d.restore();
    }

    function drawStaticFace() {
      ctx2d.save();
      ctx2d.translate(W / 2, H / 2);
      ctx2d.scale(ART_SCALE, ART_SCALE);
      ctx2d.translate(-W / 2, -H / 2);
      drawLayers(staticLayers);
      ctx2d.restore();
    }

    function drawMouth(name: string, alpha = 1, scaleX = 1, scaleY = 1, offsetY = 0) {
      ctx2d.save();
      ctx2d.translate(W / 2, H / 2 + offsetY);
      ctx2d.scale(ART_SCALE * scaleX, ART_SCALE * scaleY);
      ctx2d.translate(-W / 2, -H / 2);
      drawLayers(mouthLayers[name], alpha);
      ctx2d.restore();
    }

    function renderTransition(fromName: string, toName: string, progress: number) {
      const eased = smootherstep(progress);
      const blendStart = 0.34;
      const blendEnd = 0.66;

      if (eased < blendStart) {
        const phase = smoothstep(eased / blendStart);
        drawMouth(fromName, 1, 1 + phase * 0.018, 1 - phase * 0.07, -phase * 0.65);
        return;
      }

      if (eased > blendEnd) {
        const phase = smoothstep((eased - blendEnd) / (1 - blendEnd));
        drawMouth(toName, 1, 1.018 - phase * 0.018, 0.93 + phase * 0.07, (1 - phase) * 0.9);
        return;
      }

      const blend = (eased - blendStart) / (blendEnd - blendStart);
      drawMouth(fromName, 1 - blend, 1.018, 0.93, -0.65);
      drawMouth(toName, blend, 1.018, 0.93, 0.9);
    }

    function render(timestamp: number) {
      prepareCanvas();
      ctx2d.clearRect(0, 0, W, H);
      drawStaticFace();

      const activeTime = paused ? pauseTime - pausedTotal : timestamp - pausedTotal;
      const loopTime = ((activeTime % LOOP) + LOOP) % LOOP;
      const index = Math.floor(loopTime / SEGMENT);
      const local = loopTime - index * SEGMENT;
      const current = sequence[index];
      const next = sequence[(index + 1) % sequence.length];

      if (paused || local <= HOLD) {
        drawMouth(current);
      } else {
        renderTransition(current, next, (local - HOLD) / TRANSITION);
      }

      frame = requestAnimationFrame(render);
    }

    function togglePause() {
      if (paused) {
        pausedTotal += performance.now() - pauseTime;
        paused = false;
      } else {
        pauseTime = performance.now();
        paused = true;
      }
    }

    prepareCanvas();
    frame = requestAnimationFrame(render);
    canvasEl.addEventListener("click", togglePause);
    window.addEventListener("resize", prepareCanvas, { passive: true });

    return () => {
      cancelAnimationFrame(frame);
      canvasEl.removeEventListener("click", togglePause);
      window.removeEventListener("resize", prepareCanvas);
    };
  }, []);

  return (
    <canvas
      ref={canvasRef}
      className={styles.faceCanvas}
      role="img"
      aria-label="Smooth animated sunglasses face with a transparent background"
    />
  );
}
